import React, { useState, useEffect, useContext } from 'react';
import { Link } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import api from '../services/api';

const Dashboard = () => {
  const { user } = useContext(AuthContext);
  const [stats, setStats] = useState({
    projects: 0,
    sprints: 0,
    tasks: 0,
    completedTasks: 0
  });
  const [recentProjects, setRecentProjects] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const [projectsRes, sprintsRes, tasksRes] = await Promise.all([
        api.get('/projects'),
        api.get('/sprints'),
        api.get('/tasks')
      ]);

      const projects = projectsRes.data.projects || [];
      const sprints = sprintsRes.data.sprints || [];
      const tasks = tasksRes.data.tasks || [];

      setStats({
        projects: projects.length,
        sprints: sprints.length,
        tasks: tasks.length,
        completedTasks: tasks.filter(t => t.status === 'Completed').length
      });

      setRecentProjects(projects.slice(0, 5));
      setLoading(false);
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="loading">Loading dashboard...</div>;
  }

  return (
    <div>
      <h1>Dashboard</h1>
      <p>Welcome back, {user.name}!</p>

      <div className="grid" style={{ marginTop: '30px' }}>
        <div className="card">
          <h3>Projects</h3>
          <div style={{ fontSize: '32px', fontWeight: 'bold', color: '#007bff' }}>
            {stats.projects}
          </div>
        </div>
        <div className="card">
          <h3>Sprints</h3>
          <div style={{ fontSize: '32px', fontWeight: 'bold', color: '#28a745' }}>
            {stats.sprints}
          </div>
        </div>
        <div className="card">
          <h3>Total Tasks</h3>
          <div style={{ fontSize: '32px', fontWeight: 'bold', color: '#ffc107' }}>
            {stats.tasks}
          </div>
        </div>
        <div className="card">
          <h3>Completed Tasks</h3>
          <div style={{ fontSize: '32px', fontWeight: 'bold', color: '#17a2b8' }}>
            {stats.completedTasks}
          </div>
        </div>
      </div>

      <div className="card" style={{ marginTop: '30px' }}>
        <div className="card-header">Recent Projects</div>
        {recentProjects.length === 0 ? (
          <p>No projects yet. {user.role === 'PM' && <Link to="/projects">Create one</Link>}</p>
        ) : (
          <table className="table">
            <thead>
              <tr>
                <th>Name</th>
                <th>Team Members</th>
                <th>Risk Level</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {recentProjects.map(project => (
                <tr key={project._id}>
                  <td>{project.name}</td>
                  <td>{project.teamMembers?.length || 0}</td>
                  <td>
                    <span className={`risk-${project.riskLevel?.toLowerCase()}`}>
                      {project.riskLevel || 'Low'}
                    </span>
                  </td>
                  <td>
                    <Link to={`/projects/${project._id}`} className="btn btn-primary btn-sm">
                      View
                    </Link>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default Dashboard;
